import { useState } from 'react';

function RegistrationForm() {
  const [formData, setFormData] = useState({
    nom: '',
    email: '',
    filiere: 'Informatique',
    niveau: 'Licence 1',
    conditions: false,
    commentaire: ''
  });
  const [submitted, setSubmitted] = useState(false);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    setSubmitted(true);
    console.log('Inscription:', formData);
  };

  if (submitted) {
    return (
      &lt;div className="confirmation"&gt;
        &lt;h2&gt;Inscription enregistrée !&lt;/h2&gt;
        &lt;pre&gt;{JSON.stringify(formData, null, 2)}&lt;/pre&gt;
      &lt;/div&gt;
    );
  }

  return (
    &lt;form onSubmit={handleSubmit}&gt;
      &lt;div&gt;
        &lt;label&gt;Nom complet :&lt;/label&gt;
        &lt;input type="text" name="nom" value={formData.nom} onChange={handleChange} required /&gt;
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Email académique :&lt;/label&gt;
        &lt;input type="email" name="email" value={formData.email} onChange={handleChange} required /&gt;
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Filière :&lt;/label&gt;
        &lt;select name="filiere" value={formData.filiere} onChange={handleChange}&gt;
          &lt;option&gt;Informatique&lt;/option&gt;
          &lt;option&gt;Génie Civil&lt;/option&gt;
          &lt;option&gt;Médecine&lt;/option&gt;
          &lt;option&gt;Droit&lt;/option&gt;
        &lt;/select&gt;
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Niveau :&lt;/label&gt;
        {['Licence 1', 'Licence 2', 'Licence 3', 'Master 1', 'Master 2'].map(n => (
          &lt;label key={n}&gt;
            &lt;input type="radio" name="niveau" value={n} checked={formData.niveau === n} onChange={handleChange} /&gt;
            {n}
          &lt;/label&gt;
        ))}
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;
          &lt;input type="checkbox" name="conditions" checked={formData.conditions} onChange={handleChange} /&gt;
          J'accepte les conditions d'utilisation
        &lt;/label&gt;
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Commentaire (facultatif) :&lt;/label&gt;
        &lt;textarea name="commentaire" value={formData.commentaire} onChange={handleChange} rows="3" /&gt;
      &lt;/div&gt;

      &lt;button type="submit" disabled={!formData.conditions}&gt;S'inscrire&lt;/button&gt;
    &lt;/form&gt;
  );
}

export default RegistrationForm;
