import { useState } from 'react';

function OrderForm({ prixArticles = 0 }) {
  const [form, setForm] = useState({
    nom: '',
    telephone: '',
    adresse: '',
    ville: 'Douala',
    modePaiement: ''
  });
  const [errors, setErrors] = useState({});

  const fraisLivraison = form.ville === 'Douala' ? 500 : 1000;
  const montantTotal = prixArticles + fraisLivraison;

  const validateField = (name, value) => {
    switch(name) {
      case 'nom':
        return value.trim().length >= 3 ? '' : 'Le nom doit contenir au moins 3 caractères';
      case 'telephone':
        const phoneRegex = /^[67][0-9]{7}$/;
        return phoneRegex.test(value) ? '' : 'Téléphone invalide (ex: 612345678 ou 789012345)';
      case 'adresse':
        return value.trim() !== '' ? '' : 'L\'adresse est obligatoire';
      case 'ville':
        return value !== '' ? '' : 'Veuillez sélectionner une ville';
      case 'modePaiement':
        return value !== '' ? '' : 'Veuillez choisir un mode de paiement';
      default:
        return '';
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
    const error = validateField(name, value);
    setErrors(prev => ({ ...prev, [name]: error }));
  };

  const isFormValid = () => {
    const requiredFields = ['nom', 'telephone', 'adresse', 'ville', 'modePaiement'];
    return requiredFields.every(field => {
      const value = form[field];
      const error = validateField(field, value);
      return error === '' && value !== '';
    });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (isFormValid()) {
      alert(`Commande validée ! Montant total : ${montantTotal} FCFA`);
      console.log('Commande:', { ...form, montantTotal, prixArticles, fraisLivraison });
    }
  };

  return (
    &lt;form onSubmit={handleSubmit}&gt;
      &lt;div&gt;
        &lt;label&gt;Nom complet :&lt;/label&gt;
        &lt;input name="nom" value={form.nom} onChange={handleChange} /&gt;
        {errors.nom && &lt;span className="error"&gt;{errors.nom}&lt;/span&gt;}
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Téléphone :&lt;/label&gt;
        &lt;input name="telephone" value={form.telephone} onChange={handleChange} placeholder="612345678" /&gt;
        {errors.telephone && &lt;span className="error"&gt;{errors.telephone}&lt;/span&gt;}
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Adresse de livraison :&lt;/label&gt;
        &lt;textarea name="adresse" value={form.adresse} onChange={handleChange} rows="2" /&gt;
        {errors.adresse && &lt;span className="error"&gt;{errors.adresse}&lt;/span&gt;}
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Ville :&lt;/label&gt;
        &lt;select name="ville" value={form.ville} onChange={handleChange}&gt;
          &lt;option value="Douala"&gt;Douala&lt;/option&gt;
          &lt;option value="Yaoundé"&gt;Yaoundé&lt;/option&gt;
          &lt;option value="Garoua"&gt;Garoua&lt;/option&gt;
          &lt;option value="Bafoussam"&gt;Bafoussam&lt;/option&gt;
          &lt;option value="Bamenda"&gt;Bamenda&lt;/option&gt;
        &lt;/select&gt;
      &lt;/div&gt;

      &lt;div&gt;
        &lt;label&gt;Mode de paiement :&lt;/label&gt;
        &lt;select name="modePaiement" value={form.modePaiement} onChange={handleChange}&gt;
          &lt;option value=""&gt;-- Choisir --&lt;/option&gt;
          &lt;option value="mtn"&gt;MTN Mobile Money&lt;/option&gt;
          &lt;option value="orange"&gt;Orange Money&lt;/option&gt;
          &lt;option value="carte"&gt;Carte bancaire&lt;/option&gt;
          &lt;option value="livraison"&gt;Paiement à la livraison&lt;/option&gt;
        &lt;/select&gt;
        {errors.modePaiement && &lt;span className="error"&gt;{errors.modePaiement}&lt;/span&gt;}
      &lt;/div&gt;

      &lt;div className="total"&gt;
        &lt;p&gt;Prix des articles : {prixArticles.toLocaleString()} FCFA&lt;/p&gt;
        &lt;p&gt;Frais de livraison : {fraisLivraison.toLocaleString()} FCFA&lt;/p&gt;
        &lt;p&gt;&lt;strong&gt;Total : {montantTotal.toLocaleString()} FCFA&lt;/strong&gt;&lt;/p&gt;
      &lt;/div&gt;

      &lt;button type="submit" disabled={!isFormValid()}&gt;
        Valider la commande
      &lt;/button&gt;
    &lt;/form&gt;
  );
}

export default OrderForm;
